'use client'

import { useEffect, useState } from 'react'
import {
  DEFAULT_USER_SETTINGS,
  getBrowserTimezone,
  USER_SETTINGS_STORAGE_KEY,
  type UserSettings,
} from '@/lib/types/user-settings'
import { resetToDefaults } from '@/lib/utils/settings-utils'

/**
 * Fetch default settings from backend API
 * Returns null if backend is unavailable or has no custom defaults
 */
async function fetchBackendDefaults(): Promise<Partial<UserSettings> | null> {
  try {
    const response = await fetch('/api/v1/dashboard/settings?hostId=0')
    if (!response.ok) return null

    const data = (await response.json()) as {
      success?: boolean
      data?: { params?: Record<string, string> }
    }

    if (data.success && data.data?.params) {
      const { params } = data.data
      const defaults: Partial<UserSettings> = {}

      // Extract timezone from backend params if available
      if (params.timezone && typeof params.timezone === 'string') {
        defaults.timezone = params.timezone
      }

      // Extract theme from backend params if available
      if (params.theme && typeof params.theme === 'string') {
        defaults.theme = params.theme as UserSettings['theme']
      }

      return defaults
    }
  } catch (error) {
    console.warn('Failed to fetch backend defaults:', error)
  }
  return null
}

function loadSettings(): UserSettings {
  if (typeof window === 'undefined') return DEFAULT_USER_SETTINGS

  try {
    const stored = localStorage.getItem(USER_SETTINGS_STORAGE_KEY)
    if (stored) {
      const parsed = JSON.parse(stored) as Partial<UserSettings>
      // Merge with defaults to handle new properties from updates
      return migrateSettings({ ...DEFAULT_USER_SETTINGS, ...parsed })
    }
  } catch (error) {
    console.error('Failed to load user settings:', error)
  }

  // No stored settings - use browser timezone as default
  return {
    ...DEFAULT_USER_SETTINGS,
    timezone: getBrowserTimezone(),
  }
}

/**
 * Migrate settings from older versions
 * Ensures all new properties have their default values
 */
function migrateSettings(settings: UserSettings): UserSettings {
  return {
    ...DEFAULT_USER_SETTINGS,
    ...settings,
  }
}

function saveSettings(settings: UserSettings): void {
  if (typeof window === 'undefined') return

  try {
    localStorage.setItem(USER_SETTINGS_STORAGE_KEY, JSON.stringify(settings))
  } catch (error) {
    console.error('Failed to save user settings:', error)
  }
}

export function useUserSettings() {
  const [settings, setSettings] = useState<UserSettings>(DEFAULT_USER_SETTINGS)
  const [mounted, setMounted] = useState(false)

  // Load from localStorage after hydration, with backend defaults as fallback
  useEffect(() => {
    async function loadSettingsWithDefaults() {
      const stored = loadSettings()

      // If no stored settings, try to fetch defaults from backend
      if (!localStorage.getItem(USER_SETTINGS_STORAGE_KEY)) {
        const backendDefaults = await fetchBackendDefaults()
        if (backendDefaults) {
          const mergedSettings = {
            ...DEFAULT_USER_SETTINGS,
            ...backendDefaults,
          }
          setSettings(mergedSettings)
          saveSettings(mergedSettings)
          setMounted(true)
          return
        }

        // No backend defaults - use browser timezone and save to localStorage
        const browserDefaults = {
          ...DEFAULT_USER_SETTINGS,
          timezone: getBrowserTimezone(),
        }
        setSettings(browserDefaults)
        saveSettings(browserDefaults)
        setMounted(true)
        return
      }

      setSettings(stored)
      setMounted(true)
    }

    loadSettingsWithDefaults()
  }, [])

  const updateSettings = (updates: Partial<UserSettings>) => {
    const newSettings = { ...settings, ...updates }
    setSettings(newSettings)
    saveSettings(newSettings)
  }

  const resetSettings = (backendDefaults?: Partial<UserSettings>) => {
    const newSettings = resetToDefaults(settings, backendDefaults)
    setSettings(newSettings)
    saveSettings(newSettings)
  }

  return { settings, updateSettings, resetSettings, mounted }
}

'use client'

import useSWR, { type SWRConfiguration } from 'swr'

import type { ApiResponseMetadata } from '@/lib/api/types'
import type {
  ChartDataPoint,
  ChartQueryParams as TypedChartQueryParams,
} from '@/types/chart-data'

import { REFRESH_INTERVAL, type RefreshInterval } from './config'
import { useAdaptiveInterval } from './use-adaptive-polling'
import { useCallback, useMemo, useRef } from 'react'
import { useUserSettings } from '@/lib/hooks/use-user-settings'

/**
 * Chart metadata - re-export ApiResponseMetadata for convenience
 * This ensures the same type is used on both API and frontend
 */
export type ChartMetadata = ApiResponseMetadata

/**
 * Chart data response structure from the API
 * Can be either an array (single query) or an object (multi-query)
 */
interface ChartDataResponse<T = unknown> {
  data: T[] | Record<string, unknown>
  metadata: ChartMetadata
}

/** Error from a failed revalidation (data is stale) */
export interface StaleError extends Error {
  timestamp: number
  type?: string
  details?: { missingTables?: readonly string[]; [key: string]: unknown }
}

/** Return type from useChartData hook */
export interface UseChartResult<TData extends ChartDataPoint = ChartDataPoint> {
  data: TData[]
  metadata?: ChartMetadata
  sql?: string
  error?: Error
  isLoading: boolean
  isValidating: boolean
  mutate: () => Promise<undefined | unknown>
  /** True when data exists (even if stale due to revalidation error) */
  hasData: boolean
  /** Error from failed revalidation (only set when data exists but refresh failed) */
  staleError?: StaleError
}

export type SwrConfigPreset = keyof typeof REFRESH_INTERVAL | SWRConfiguration

export interface UseChartDataParams {
  chartName: string
  hostId?: number | string
  interval?: string
  lastHours?: number
  params?: TypedChartQueryParams['params']
  /** Refresh interval in ms OR use REFRESH_INTERVAL constants */
  refreshInterval?: RefreshInterval | number
  /** Additional SWR config options */
  swrConfig?: SWRConfiguration
  /** Enable adaptive polling (default: true) - slows polling when tab is inactive */
  adaptive?: boolean
}

/**
 * Hook to fetch chart data using SWR
 * Makes GET request to /api/v1/charts/[chartName]
 *
 * @template T - The chart data point type
 * @param {UseChartDataParams} params - Configuration object
 * @returns {UseChartResult<T>} SWR state object with data array, metadata, error, isLoading, isValidating, and mutate function
 *
 * @example
 * ```typescript
 * // Using default refresh interval (30s)
 * const { data, metadata, error, isLoading } = useChartData({
 *   chartName: 'query-performance',
 *   hostId: 1,
 *   interval: 'toStartOfHour',
 *   lastHours: 24,
 * })
 *
 * // Using preset refresh interval
 * import { REFRESH_INTERVAL } from '@/lib/swr/config'
 * const { data } = useChartData({
 *   chartName: 'query-performance',
 *   refreshInterval: REFRESH_INTERVAL.FAST_15S,
 * })
 * ```
 */
export function useChartData<T extends ChartDataPoint = ChartDataPoint>({
  chartName,
  hostId,
  interval,
  lastHours,
  params,
  refreshInterval = REFRESH_INTERVAL.DEFAULT_60S,
  swrConfig,
  adaptive = true,
}: UseChartDataParams): UseChartResult<T> {
  // Get user settings (including timezone) for API requests
  const { settings } = useUserSettings()

  // Get adaptive refresh interval (slows down when tab is inactive)
  // If user disabled auto-refresh, respect that setting
  const baseInterval = settings.autoRefresh ? refreshInterval : 0
  const adaptiveInterval = useAdaptiveInterval(adaptive ? baseInterval : 0)

  // Use the adapted interval for SWR, or original if adaptive is disabled
  const effectiveInterval =
    adaptive && adaptiveInterval > 0
      ? adaptiveInterval
      : baseInterval > 0
        ? baseInterval
        : 0

  // Build query parameters
  const searchParams = new URLSearchParams()
  if (hostId !== undefined) searchParams.append('hostId', String(hostId))
  if (interval) searchParams.append('interval', interval)
  // Only include lastHours if it's defined (undefined = "all" range, no time filter)
  if (lastHours !== undefined)
    searchParams.append('lastHours', String(lastHours))
  if (params) searchParams.append('params', JSON.stringify(params))
  // Pass timezone to ClickHouse for session-level time conversion
  if (settings.timezone) searchParams.append('timezone', settings.timezone)

  const queryString = searchParams.toString()
  const url = `/api/v1/charts/${chartName}${queryString ? `?${queryString}` : ''}`

  // Build cache key - stringify params to ensure consistent caching
  // (identical param objects with different references should share cache)
  // Include timezone so cache invalidates when user changes timezone
  const key = [
    '/api/v1/charts',
    chartName,
    hostId,
    interval,
    lastHours,
    JSON.stringify(params || null),
    settings.timezone,
  ]

  // Fetcher function (memoized with useCallback to prevent recreation on every render)
  const fetcher = useCallback(async () => {
    const response = await fetch(url)

    if (!response.ok) {
      const errorData = (await response.json().catch(() => ({}))) as {
        error?: {
          message?: string
          type?: string
          details?: {
            missingTables?: readonly string[]
            [key: string]: unknown
          }
        }
      }
      const error = new Error(
        errorData.error?.message ||
          `Failed to fetch chart data: ${response.statusText}`
      ) as Error & {
        type?: string
        details?: { missingTables?: readonly string[]; [key: string]: unknown }
      }

      // Attach error metadata if available
      if (errorData.error) {
        error.type = errorData.error.type
        error.details = errorData.error.details
      }

      throw error
    }

    return response.json() as Promise<ChartDataResponse<T>>
  }, [url])

  const { data, error, isLoading, isValidating, mutate } = useSWR<
    ChartDataResponse<T>,
    Error
  >(key, fetcher, {
    revalidateIfStale: true,
    revalidateOnReconnect: true,
    dedupingInterval: 5000,
    focusThrottleInterval: 5000,
    refreshInterval: effectiveInterval,
    ...swrConfig,
  })

  // Handle both array (single query) and object (multi-query) data structures
  // Multi-query charts return: { main: [...], totalMem: [...], ... }
  // Single-query charts return: [{ ... }, { ... }, ... ]
  const dataArray =
    Array.isArray(data?.data) || !data?.data
      ? (data?.data as T[])
      : ([data.data] as T[])

  // Check if we have valid data (even if there's an error from revalidation)
  const hasData = Boolean(dataArray && dataArray.length > 0)

  // Track timestamp for stale errors - use ref to persist across renders
  const staleErrorTimestampRef = useRef<number>(0)

  // Create staleError only when we have data but revalidation failed
  // This distinguishes "initial load error" from "revalidation error"
  const staleError = useMemo<StaleError | undefined>(() => {
    if (!error || !hasData || isLoading) {
      // No error, no data, or still loading - clear stale error
      staleErrorTimestampRef.current = 0
      return undefined
    }

    // We have data AND an error (revalidation failed)
    // Use existing timestamp if this is the same error, otherwise create new
    if (staleErrorTimestampRef.current === 0) {
      staleErrorTimestampRef.current = Date.now()
    }

    return {
      ...error,
      name: error.name,
      message: error.message,
      timestamp: staleErrorTimestampRef.current,
      type: (error as Error & { type?: string }).type,
      details: (error as Error & { details?: StaleError['details'] }).details,
    }
  }, [error, hasData, isLoading])

  return {
    data: dataArray,
    metadata: data?.metadata,
    sql: data?.metadata?.sql,
    error,
    isLoading,
    isValidating,
    mutate,
    hasData,
    staleError,
  }
}

'use client'

import useSWR, { type SWRConfiguration } from 'swr'

import type { ApiResponseMetadata } from '@/lib/api/types'
import type { StaleError } from './use-chart-data'

import { useAdaptiveInterval } from './use-adaptive-polling'
import { useMemo, useRef } from 'react'
import { useUserSettings } from '@/lib/hooks/use-user-settings'

/**
 * Table data response structure from the API
 * Extends the standard ApiResponse with table-specific metadata
 */
export interface TableDataResponse<T = unknown> {
  /** Array of table row data */
  data: T[]
  /** Response metadata including query execution info */
  metadata: ApiResponseMetadata & {
    /** Additional ClickHouse-specific metadata */
    rows_before_limit_at_least?: number
    exception?: string
  }
}

/**
 * Query parameters for table data requests
 */
export interface TableQueryParams {
  search?: string
  sortBy?: string
  sortOrder?: 'asc' | 'desc'
  page?: number
  limit?: number
  [key: string]: string | number | boolean | undefined
}

/**
 * Hook to fetch table data using SWR
 * Makes GET request to /api/v1/tables/[queryConfigName]
 *
 * @template T - The table row data type
 * @param {string} queryConfigName - Name of the query configuration to use
 * @param {number} [hostId] - Host ID for the request
 * @param {TableQueryParams} [searchParams] - Query parameters (search, sort, pagination, etc.)
 * @param {number} [refreshInterval] - Auto-refresh interval in milliseconds (disabled if 0 or undefined)
 * @param {SWRConfiguration} [swrConfig] - Additional SWR configuration options
 * @param {boolean} [adaptive] - Enable adaptive polling (default: true) - slows polling when tab is inactive
 * @returns {Object} SWR state object with data array, metadata, error, isLoading, isValidating, and refresh function
 *
 * @example
 * ```typescript
 * const { data, metadata, error, isLoading, isValidating, mutate } = useTableData(
 *   'tables',
 *   1,
 *   { search: 'log', page: 1, limit: 10 }
 * )
 * ```
 */
export function useTableData<T = unknown>(
  queryConfigName: string,
  hostId?: number,
  searchParams?: TableQueryParams,
  refreshInterval?: number,
  swrConfig?: SWRConfiguration,
  adaptive = true
) {
  // Get user settings (including timezone) for API requests
  const { settings } = useUserSettings()

  // Get adaptive refresh interval (slows down when tab is inactive)
  // If user disabled auto-refresh, respect that setting
  const baseInterval =
    settings.autoRefresh && refreshInterval ? refreshInterval : 0
  const adaptiveInterval = useAdaptiveInterval(
    adaptive && baseInterval ? baseInterval : 0
  )

  // Use the adapted interval for SWR, or original if adaptive is disabled
  const effectiveInterval =
    adaptive && adaptiveInterval > 0
      ? adaptiveInterval
      : baseInterval > 0
        ? baseInterval
        : 0

  // Build query string from search parameters
  const params = new URLSearchParams()
  if (hostId !== undefined) params.append('hostId', String(hostId))

  if (searchParams) {
    Object.entries(searchParams).forEach(([key, value]) => {
      if (value !== undefined && value !== null && value !== '') {
        params.append(key, String(value))
      }
    })
  }

  // Pass timezone to ClickHouse for session-level time conversion
  if (settings.timezone) params.append('timezone', settings.timezone)

  const queryString = params.toString()
  const url = `/api/v1/tables/${queryConfigName}${queryString ? `?${queryString}` : ''}`

  // Build cache key - include all parameters that affect the data
  // Include timezone so cache invalidates when user changes timezone
  const key = [
    '/api/v1/tables',
    queryConfigName,
    hostId,
    JSON.stringify(searchParams || {}),
    settings.timezone,
  ]

  // Fetcher function
  const fetcher = async () => {
    const response = await fetch(url)

    if (!response.ok) {
      const errorData = (await response.json().catch(() => ({}))) as {
        error?: {
          message?: string
          type?: string
          details?: {
            missingTables?: readonly string[]
            [key: string]: unknown
          }
        }
      }
      const error = new Error(
        errorData.error?.message ||
          `Failed to fetch table data: ${response.statusText}`
      ) as Error & {
        type?: string
        details?: { missingTables?: readonly string[]; [key: string]: unknown }
      }

      // Attach error metadata if available
      if (errorData.error) {
        error.type = errorData.error.type
        error.details = errorData.error.details
      }

      throw error
    }

    return response.json() as Promise<TableDataResponse<T>>
  }

  const { data, error, isLoading, isValidating, mutate } = useSWR<
    TableDataResponse<T>,
    Error
  >(key, fetcher, {
    revalidateIfStale: true,
    revalidateOnReconnect: true,
    dedupingInterval: 3000,
    focusThrottleInterval: 5000,
    refreshInterval: effectiveInterval,
    ...swrConfig,
  })

  // Check if we have valid data (even if there's an error from revalidation)
  const dataArray = data?.data || []
  const hasData = dataArray.length > 0

  // Track timestamp for stale errors - use ref to persist across renders
  const staleErrorTimestampRef = useRef<number>(0)

  // Create staleError only when we have data but revalidation failed
  // This distinguishes "initial load error" from "revalidation error"
  const staleError = useMemo<StaleError | undefined>(() => {
    if (!error || !hasData || isLoading) {
      // No error, no data, or still loading - clear stale error
      staleErrorTimestampRef.current = 0
      return undefined
    }

    // We have data AND an error (revalidation failed)
    // Use existing timestamp if this is the same error, otherwise create new
    if (staleErrorTimestampRef.current === 0) {
      staleErrorTimestampRef.current = Date.now()
    }

    return {
      ...error,
      name: error.name,
      message: error.message,
      timestamp: staleErrorTimestampRef.current,
      type: (error as Error & { type?: string }).type,
      details: (error as Error & { details?: StaleError['details'] }).details,
    }
  }, [error, hasData, isLoading])

  return {
    data: dataArray,
    metadata: data?.metadata,
    error,
    isLoading,
    isValidating,
    refresh: mutate,
    /** True when data exists (even if stale due to revalidation error) */
    hasData,
    /** Error from failed revalidation (only set when data exists but refresh failed) */
    staleError,
  }
}

'use client'

import { Check, ChevronsUpDown } from 'lucide-react'

import { HostStatusDropdown } from './host-status-dropdown'
import { HostVersionWithStatus } from './host-version-status'
import {
  LogoStatusIndicator,
  LogoStatusIndicatorSkeleton,
} from './logo-status-indicator'
import { usePathname, useRouter, useSearchParams } from 'next/navigation'
import { useCallback } from 'react'
import { ClickHouseLogo } from '@/components/icons/clickhouse-logo'
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu'
import {
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
  useSidebar,
} from '@/components/ui/sidebar'
import { Skeleton } from '@/components/ui/skeleton'
import { useHostId } from '@/lib/swr'
import { useHosts } from '@/lib/swr/use-hosts'
import { buildUrl } from '@/lib/url/url-builder'
import { getHost } from '@/lib/utils'

/**
 * Host switcher component for sidebar header.
 *
 * Provides dropdown menu for switching between ClickHouse hosts.
 * Shows host icon, name, and status in collapsed/expanded states.
 */
export function HostSwitcher() {
  const router = useRouter()
  const pathname = usePathname()
  const searchParams = useSearchParams()
  const { isMobile, state } = useSidebar()
  const { hosts, isLoading } = useHosts()
  const currentHostId = useHostId()

  const activeHost = hosts[currentHostId] || hosts[0]

  const handleHostChange = useCallback(
    (hostId: number) => {
      if (hostId >= 0 && hostId < hosts.length) {
        const url = buildUrl(pathname, { host: hostId }, searchParams)
        router.push(url)
      }
    },
    [searchParams, pathname, router, hosts.length]
  )

  // Show skeleton while loading hosts
  if (isLoading) {
    return (
      <SidebarMenu>
        <SidebarMenuItem>
          <SidebarMenuButton size="lg" asChild>
            <div
              className={`flex gap-2 ${state === 'expanded' ? 'items-center' : 'items-center justify-center'}`}
            >
              <div className="relative">
                <ClickHouseLogo width={20} height={20} className="size-5" />
                {state === 'collapsed' && <LogoStatusIndicatorSkeleton />}
              </div>
              {state === 'expanded' && (
                <div className="grid flex-1 text-left text-sm leading-tight">
                  <Skeleton className="h-4 w-24" />
                  <Skeleton className="h-3 w-16" />
                </div>
              )}
            </div>
          </SidebarMenuButton>
        </SidebarMenuItem>
      </SidebarMenu>
    )
  }

  // Don't render switcher if no hosts configured
  if (!activeHost) {
    return null
  }

  // For single host, render simplified view without dropdown
  const isSingleHost = hosts.length <= 1

  return (
    <SidebarMenu>
      <SidebarMenuItem>
        {isSingleHost ? (
          // Single host: simplified display without dropdown
          <SidebarMenuButton size="lg" asChild>
            <div
              className={`flex gap-2 ${state === 'expanded' ? 'items-center' : 'items-center justify-center'}`}
            >
              <div className="relative">
                <ClickHouseLogo width={20} height={20} className="size-5" />
                {state === 'collapsed' && (
                  <LogoStatusIndicator hostId={activeHost.id} />
                )}
              </div>
              {state === 'expanded' && (
                <div className="grid flex-1 text-left text-sm leading-tight">
                  <span className="truncate font-semibold">
                    {activeHost.name || getHost(activeHost.host)}
                  </span>
                  <HostVersionWithStatus hostId={activeHost.id} />
                </div>
              )}
            </div>
          </SidebarMenuButton>
        ) : (
          // Multiple hosts: full switcher with dropdown
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <SidebarMenuButton
                size="lg"
                className="data-[state=open]:bg-sidebar-accent data-[state=open]:text-sidebar-accent-foreground"
                data-testid="host-switcher"
                aria-label={`Select ClickHouse host. Current: ${activeHost.name || getHost(activeHost.host)}`}
                asChild
              >
                <div
                  className={`flex gap-2 ${state === 'expanded' ? 'items-center' : 'items-center justify-center'}`}
                >
                  <div className="relative">
                    <ClickHouseLogo width={20} height={20} className="size-5" />
                    {state === 'collapsed' && (
                      <LogoStatusIndicator hostId={activeHost.id} />
                    )}
                  </div>
                  {state === 'expanded' && (
                    <>
                      <div className="grid flex-1 text-left text-sm leading-tight">
                        <span className="truncate font-semibold">
                          {activeHost.name || getHost(activeHost.host)}
                        </span>
                        <HostVersionWithStatus hostId={activeHost.id} />
                      </div>
                      <ChevronsUpDown className="ml-auto size-4" />
                    </>
                  )}
                </div>
              </SidebarMenuButton>
            </DropdownMenuTrigger>
            <DropdownMenuContent
              className="w-[--radix-dropdown-menu-trigger-width] min-w-56 rounded-lg"
              align="start"
              side={isMobile ? 'bottom' : 'right'}
              sideOffset={4}
            >
              <DropdownMenuLabel className="text-xs text-muted-foreground">
                ClickHouse Hosts
              </DropdownMenuLabel>
              <DropdownMenuSeparator />
              {hosts.map((host, index) => (
                <DropdownMenuItem
                  key={host.host + host.id}
                  onClick={() => handleHostChange(index)}
                  className="gap-2 p-2"
                  data-testid={`host-option-${index}`}
                >
                  <div className="flex flex-1 items-center gap-2">
                    <span className="truncate">
                      {host.name || getHost(host.host)}
                    </span>
                    <HostStatusDropdown hostId={host.id} />
                  </div>
                  {index === currentHostId && (
                    <Check className="ml-auto size-4" />
                  )}
                </DropdownMenuItem>
              ))}
            </DropdownMenuContent>
          </DropdownMenu>
        )}
      </SidebarMenuItem>
    </SidebarMenu>
  )
}

/**
 * Hosts list endpoint
 * GET /api/v1/hosts
 *
 * Returns information about all configured ClickHouse hosts
 * Excludes sensitive information like passwords
 */

import { createErrorResponse as createApiErrorResponse } from '@/lib/api/error-handler'
import {
  CacheControl,
  createSuccessResponse,
} from '@/lib/api/shared/response-builder'
import { ApiErrorType } from '@/lib/api/types'
import { getClickHouseConfigs } from '@/lib/clickhouse'
import { debug, error, generateRequestId } from '@/lib/logger'
import { getHost } from '@/lib/utils'

// This route is dynamic and should not be statically exported
export const dynamic = 'force-dynamic'

const ROUTE_CONTEXT = { route: '/api/v1/hosts', method: 'GET' }

/**
 * Host information for public API responses
 */
export interface HostInfo {
  readonly id: number
  readonly name: string
  readonly host: string
  readonly user: string
}

/**
 * Handle GET requests for hosts list
 */
export async function GET(): Promise<Response> {
  const requestId = generateRequestId()
  debug('[GET /api/v1/hosts] Fetching host configurations', { requestId })

  try {
    // Get all configured hosts
    const configs = getClickHouseConfigs()

    // Transform to public API format (exclude passwords)
    const hosts: HostInfo[] = configs.map((config) => ({
      id: config.id,
      name: config.customName || getHost(config.host) || `Host ${config.id}`,
      host: config.host,
      user: config.user,
    }))

    // Create response with standardized builder
    const response = createSuccessResponse(hosts, {
      queryId: 'hosts-list',
      rows: hosts.length,
    })

    // Add request ID header
    const newHeaders = new Headers(response.headers)
    newHeaders.set('X-Request-ID', requestId)
    newHeaders.set('Cache-Control', CacheControl.LONG)

    return new Response(response.body, {
      status: response.status,
      statusText: response.statusText,
      headers: newHeaders,
    })
  } catch (err) {
    const errorMessage =
      err instanceof Error ? err.message : 'Unknown error occurred'

    error('[GET /api/v1/hosts] Error:', err, { requestId })

    const errorResponse = createApiErrorResponse(
      {
        type: ApiErrorType.QueryError,
        message: errorMessage,
        details: {
          timestamp: new Date().toISOString(),
        },
      },
      500,
      ROUTE_CONTEXT
    )

    // Add request ID header to error response
    const errorHeaders = new Headers(errorResponse.headers)
    errorHeaders.set('X-Request-ID', requestId)

    return new Response(errorResponse.body, {
      status: errorResponse.status,
      statusText: errorResponse.statusText,
      headers: errorHeaders,
    })
  }
}

/**
 * ClickHouse Client Types
 * Shared types for ClickHouse client and data fetching
 */

import type { QueryParams } from '@clickhouse/client'

export type ClickHouseConfig = {
  id: number
  host: string
  user: string
  password: string
  customName?: string
}

/** @deprecated Reserved for future use */
type _QuerySettings = QueryParams['clickhouse_settings'] &
  Partial<{
    // @since 24.4
    query_cache_system_table_handling: 'throw' | 'save' | 'ignore'
    query_cache_nondeterministic_function_handling: 'throw' | 'save' | 'ignore'
  }>

export type FetchDataErrorType =
  | 'table_not_found'
  | 'validation_error'
  | 'query_error'
  | 'network_error'
  | 'permission_error'

export interface FetchDataError {
  readonly type: FetchDataErrorType
  readonly message: string
  readonly details?: {
    readonly missingTables?: readonly string[]
    readonly queryId?: string
    readonly originalError?: Error
    readonly host?: string
  }
}

export interface FetchDataResult<T> {
  readonly data: T | null
  readonly metadata: Record<string, string | number>
  readonly error?: FetchDataError
}

/**
 * Generic data endpoint for executing ClickHouse queries
 * POST /api/v1/data, GET /api/v1/data
 *
 * Accepts a query and parameters, returns data with metadata.
 * Includes caching headers for performance optimization.
 *
 * SECURITY: This endpoint validates that queries being executed are either:
 * 1. Pre-defined in the chart/table registries (recommended)
 * 2. Stored in the dashboard tables (for custom dashboards)
 * This prevents clients from sending arbitrary SQL queries.
 */

import type { DataFormat } from '@clickhouse/client'

import type { ApiRequest } from '@/lib/api/types'
import type { FetchDataError } from '@/lib/clickhouse'

import { validateDashboardQuery } from './validators/dashboard-query-validator'
import {
  createErrorResponse as createApiErrorResponse,
  createValidationError,
  withApiHandler,
} from '@/lib/api/error-handler'
import { createSuccessResponse } from '@/lib/api/shared/response-builder'
import { mapErrorTypeToStatusCode } from '@/lib/api/shared/status-code-mapper'
import {
  getAndValidateHostId,
  validateDataRequest,
  validateSearchParams,
  validateSqlQuery,
} from '@/lib/api/shared/validators'
import { ApiErrorType } from '@/lib/api/types'
import { fetchData } from '@/lib/clickhouse'
import { debug, error } from '@/lib/logger'

// This route is dynamic and should not be statically exported
export const dynamic = 'force-dynamic'

const ROUTE_CONTEXT = { route: '/api/v1/data' }

/**
 * Handle GET requests for data fetching
 * Accepts query and parameters via URL query string
 *
 * @example
 * GET /api/v1/data?hostId=0&sql=SELECT%20count()%20FROM%20system.tables&format=JSONEachRow
 */
export const GET = withApiHandler(async (request: Request) => {
  const url = new URL(request.url)
  const searchParams = url.searchParams

  // Parse query parameters from URL
  const query =
    searchParams.get('sql') || searchParams.get('query') || undefined
  const format = searchParams.get('format') as DataFormat | null
  const timezone = searchParams.get('timezone') || undefined

  // Validate required parameters
  const validationError = validateSearchParams(searchParams, ['hostId'])
  if (validationError) {
    return createValidationError(validationError.message, {
      ...ROUTE_CONTEXT,
      method: 'GET',
    })
  }

  if (!query) {
    return createValidationError('Missing required parameter: sql or query', {
      ...ROUTE_CONTEXT,
      method: 'GET',
    })
  }

  // SECURITY: Validate SQL query to prevent injection attacks
  try {
    validateSqlQuery(query)
  } catch (validationError) {
    error('[GET /api/v1/data] Security: SQL validation failed', {
      queryPreview: query.substring(0, 100),
      error:
        validationError instanceof Error
          ? validationError.message
          : 'Unknown error',
    })
    return createValidationError(
      validationError instanceof Error
        ? validationError.message
        : 'SQL validation failed',
      { ...ROUTE_CONTEXT, method: 'GET' }
    )
  }

  // Get and validate hostId from search params
  const hostIdResult = getAndValidateHostId(searchParams)
  if (typeof hostIdResult !== 'number') {
    return createValidationError(hostIdResult.message, {
      ...ROUTE_CONTEXT,
      method: 'GET',
    })
  }
  const hostId = hostIdResult

  debug('[GET /api/v1/data]', {
    hostId,
    format: format || 'JSONEachRow',
    timezone,
  })

  // Execute the query
  const result = await fetchData({
    query,
    format: (format || 'JSONEachRow') as DataFormat,
    hostId,
    // Pass timezone to ClickHouse for session-level time conversion
    clickhouse_settings: timezone ? { session_timezone: timezone } : undefined,
  })

  // Handle errors
  if (result.error) {
    error('[GET /api/v1/data] Query error:', result.error)
    return handleQueryError(result.error, hostId, 'GET')
  }

  // Create successful response with timezone in metadata
  return createSuccessResponse(result.data, { ...result.metadata, timezone })
}, ROUTE_CONTEXT)

/**
 * Handle POST requests for data fetching
 * Accepts query and parameters in the request body
 *
 * SECURITY: When queryConfig is not provided, validates that the query
 * exists in the dashboard tables to prevent arbitrary SQL execution.
 *
 * @example
 * POST /api/v1/data
 * {
 *   "query": "SELECT count() FROM system.tables",
 *   "hostId": 0,
 *   "format": "JSONEachRow"
 * }
 */
export const POST = withApiHandler(async (request: Request) => {
  // Parse request body
  const body = (await request.json()) as Partial<ApiRequest>

  // Validate required fields using shared validator
  const validationError = validateDataRequest(body)
  if (validationError) {
    return createApiErrorResponse(validationError, 400, {
      ...ROUTE_CONTEXT,
      method: 'POST',
    })
  }

  const typedBody = body as ApiRequest
  const {
    query,
    queryParams,
    hostId,
    format = 'JSONEachRow',
    queryConfig,
    timezone,
  } = typedBody

  debug('[POST /api/v1/data]', {
    hostId,
    format,
    queryConfig: queryConfig?.name,
    timezone,
  })

  // SECURITY: If no queryConfig provided, validate the query exists in dashboard tables
  // This prevents arbitrary SQL execution from clients
  if (!queryConfig) {
    const validationResult = await validateDashboardQuery(query, Number(hostId))
    if (!validationResult.valid) {
      error(
        '[POST /api/v1/data] Security: Query not found in dashboard tables',
        {
          queryPreview: query.substring(0, 100),
        }
      )
      return createApiErrorResponse(
        {
          type: ApiErrorType.PermissionError,
          message: validationResult.error?.message || 'Query validation failed',
        },
        403,
        { ...ROUTE_CONTEXT, method: 'POST', hostId }
      )
    }
  }

  // Convert format string to DataFormat if needed
  const dataFormat = (format || 'JSONEachRow') as DataFormat

  // Execute the query
  const result = await fetchData({
    query,
    query_params: queryParams,
    format: dataFormat,
    hostId,
    queryConfig,
    // Pass timezone to ClickHouse for session-level time conversion
    clickhouse_settings: timezone ? { session_timezone: timezone } : undefined,
  })

  // Handle errors
  if (result.error) {
    error('[POST /api/v1/data] Query error:', result.error)
    return handleQueryError(result.error, hostId, 'POST')
  }

  // Create successful response with timezone in metadata
  return createSuccessResponse(result.data, { ...result.metadata, timezone })
}, ROUTE_CONTEXT)

/**
